import React, { useState, useEffect } from 'react';
import { ShoppingBag, Clock, CheckCircle, MapPin, Loader2 } from 'lucide-react';
import { calcularDistanciaReal } from '../utils/shippingService';
import Carrito from './Carrito';
import SeguimientoPedido from './SeguimientoPedido';

const COORDS_LOCAL = { lat: -26.732479, lon: -65.267028 }; 

const PanelCliente = () => {
  const [tab, setTab] = useState('tienda'); // tienda, proceso, historial
  const [ofertas, setOfertas] = useState([]);
  const [cart, setCart] = useState([]);
  const [pedidos, setPedidos] = useState([]);
  
  // Ubicación
  const [busqueda, setBusqueda] = useState("");
  const [sugerencias, setSugerencias] = useState([]);
  const [distanciaReal, setDistanciaReal] = useState(0);
  const [cargando, setCargando] = useState(false);

  useEffect(() => {
    // Carga de ofertas desde localStorage
    const locales = JSON.parse(localStorage.getItem('mis-locales') || "[]");
    let acc = [];
    locales.forEach(l => {
      const ofs = JSON.parse(localStorage.getItem(`ofertas-local-${l.id}`) || "[]");
      acc = [...acc, ...ofs.map(o => ({ ...o, nombreLocal: l.nombre }))];
    });
    setOfertas(acc);

    // Carga de historial guardado
    const historial = JSON.parse(localStorage.getItem('historial-pedidos') || "[]");
    setPedidos(historial);
  }, []);

  const buscarDireccion = async (val) => {
    setBusqueda(val);
    if (val.length < 5) return setSugerencias([]);
    setCargando(true);
    try {
      const res = await fetch(`https://nominatim.openstreetmap.org/search?format=json&q=${val}&countrycodes=ar&limit=5&addressdetails=1`);
      const data = await res.json();
      setSugerencias(data);
    } catch (e) { 
      console.error("Error buscando dirección:", e); 
    } finally { 
      setCargando(false); 
    }
  };

  const seleccionarDireccion = (item) => {
    const d = calcularDistanciaReal(parseFloat(item.lat), parseFloat(item.lon), COORDS_LOCAL.lat, COORDS_LOCAL.lon);
    setDistanciaReal(d);
    // Guardamos una dirección limpia para el mapa y el ticket
    const direccionFormateada = `${item.address.road || ''} ${item.address.house_number || ''}, ${item.address.city || item.address.town || 'Tucumán'}`;
    setBusqueda(direccionFormateada);
    setSugerencias([]);
  };

  const handlePago = (total) => {
    if (distanciaReal === 0 && busqueda === "") {
        alert("Por favor, ingresa tu dirección antes de pagar.");
        return;
    }

    const nuevo = {
      id: `PED-${Date.now()}`,
      total,
      fecha: new Date().toLocaleString(),
      estado: 'proceso',
      distancia: distanciaReal,
      direccion: busqueda, // Pasamos la dirección al pedido para el Mapa
      items: [...cart]
    };
    
    const listaActualizada = [nuevo, ...pedidos];
    setPedidos(listaActualizada);
    localStorage.setItem('historial-pedidos', JSON.stringify(listaActualizada));
    setCart([]);
    setTab('proceso'); // Cambiamos a la pestaña de seguimiento automáticamente
  };

  const finalizarPedido = (id) => {
    const actualizados = pedidos.map(p => p.id === id ? { ...p, estado: 'completado' } : p);
    setPedidos(actualizados);
    localStorage.setItem('historial-pedidos', JSON.stringify(actualizados));
  };

  return (
    <div style={panelLayout}>
      {/* NAVEGACIÓN LATERAL */}
      <div style={sidebar}>
        <h2 style={{color: '#e67e22', marginBottom: '40px', textAlign: 'center'}}>🛒 OfertasApp</h2>
        <button onClick={() => setTab('tienda')} style={tab === 'tienda' ? btnNavActive : btnNav}>
          <ShoppingBag size={18}/> Hacer mi pedido
        </button>
        <button onClick={() => setTab('proceso')} style={tab === 'proceso' ? btnNavActive : btnNav}>
          <Clock size={18}/> En Proceso 
          {pedidos.filter(p => p.estado === 'proceso').length > 0 && 
            <span style={badge}>{pedidos.filter(p => p.estado === 'proceso').length}</span>
          }
        </button>
        <button onClick={() => setTab('historial')} style={tab === 'historial' ? btnNavActive : btnNav}>
          <CheckCircle size={18}/> Historial
        </button>
      </div>

      {/* CONTENIDO PRINCIPAL */}
      <div style={mainContent}>
        {tab === 'tienda' && (
          <div style={{display: 'flex', gap: '30px'}}>
            <div style={{flex: 1}}>
              <div style={searchBar}>
                <MapPin size={20} color="#e67e22" />
                <input 
                  style={input} 
                  placeholder="Calle y altura (Ej: Av. Alem 100)..." 
                  value={busqueda} 
                  onChange={(e) => buscarDireccion(e.target.value)} 
                />
                {cargando && <Loader2 size={18} className="animate-spin" />}
                {sugerencias.length > 0 && (
                  <div style={dropdown}>
                    {sugerencias.map((s, i) => (
                      <div key={i} style={sugItem} onClick={() => seleccionarDireccion(s)}>
                        {s.display_name.split(',').slice(0, 3).join(',')}
                      </div>
                    ))}
                  </div>
                )}
              </div>
              
              <h3 style={{marginBottom: '15px', color: '#1e293b'}}>Ofertas del día</h3>
              <div style={grid}>
                {ofertas.map(o => (
                  <div key={o.id} style={cardOferta}>
                    <img src={o.imagen || 'https://via.placeholder.com/150'} style={imgStyle} alt="" />
                    <div style={{padding: '12px'}}>
                      <small style={{color: '#e67e22', fontWeight: 'bold'}}>{o.nombreLocal}</small>
                      <h4 style={{margin: '5px 0', fontSize: '0.9rem'}}>{o.producto}</h4>
                      <button style={btnAdd} onClick={() => setCart([...cart, o])}>
                        Agregar ${o.precioNuevo}
                      </button>
                    </div>
                  </div>
                ))}
              </div>
            </div>
            
            <div style={{width: '350px'}}>
               <Carrito cart={cart} setCart={setCart} distanciaReal={distanciaReal} onCheckout={handlePago} />
            </div>
          </div>
        )}

        {tab === 'proceso' && (
          <div style={centeredContainer}>
            <h2 style={{marginBottom: '20px'}}>Sigue tu pedido</h2>
            {pedidos.filter(p => p.estado === 'proceso').length === 0 ? (
              <div style={{textAlign: 'center', padding: '40px'}}>
                <ShoppingBag size={40} color="#cbd5e1" />
                <p style={{color: '#64748b'}}>No tienes envíos activos en este momento.</p>
              </div>
            ) : (
              pedidos.filter(p => p.estado === 'proceso').map(p => (
                <SeguimientoPedido key={p.id} pedido={p} onFinalizar={finalizarPedido} />
              ))
            )}
          </div>
        )}

        {tab === 'historial' && (
          <div style={centeredContainer}>
            <h2 style={{marginBottom: '20px'}}>Pedidos Realizados</h2>
            <div style={historialList}>
              {pedidos.filter(p => p.estado === 'completado').length === 0 ? (
                <p style={{color: '#64748b', textAlign: 'center'}}>Tu historial está vacío.</p>
              ) : (
                pedidos.filter(p => p.estado === 'completado').map(p => (
                  <div key={p.id} style={historialItem}>
                    <div>
                      <div style={{fontSize: '0.8rem', color: '#64748b'}}>{p.fecha}</div>
                      <strong>Pedido #{p.id.slice(-6)}</strong>
                    </div>
                    <div style={{textAlign: 'right'}}>
                      <div style={{fontWeight: 'bold', color: '#1e293b'}}>${p.total}</div>
                      <span style={{color: '#27ae60', fontSize: '0.8rem'}}>✓ Entregado</span>
                    </div>
                  </div>
                ))
              )}
            </div>
          </div>
        )}
      </div>
    </div>
  );
};

// --- ESTILOS ---
const panelLayout = { display: 'flex', minHeight: '100vh', background: '#f8fafc' };
const sidebar = { width: '250px', background: '#1e293b', padding: '30px 20px', display: 'flex', flexDirection: 'column', gap: '10px', position: 'sticky', top: 0, height: '100vh' };
const btnNav = { display: 'flex', alignItems: 'center', gap: '10px', padding: '12px 15px', background: 'none', border: 'none', color: '#94a3b8', cursor: 'pointer', textAlign: 'left', borderRadius: '12px', width: '100%', transition: '0.3s', fontWeight: '500' };
const btnNavActive = { ...btnNav, background: '#e67e22', color: 'white' };
const badge = { background: 'white', color: '#e67e22', borderRadius: '50%', padding: '2px 8px', fontSize: '0.75rem', marginLeft: 'auto', fontWeight: 'bold' };
const mainContent = { flex: 1, padding: '40px', overflowY: 'auto' };
const searchBar = { display: 'flex', alignItems: 'center', background: 'white', padding: '14px 20px', borderRadius: '18px', position: 'relative', border: '1px solid #e2e8f0', marginBottom: '30px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)' };
const input = { flex: 1, border: 'none', outline: 'none', marginLeft: '10px', fontSize: '1rem' };
const dropdown = { position: 'absolute', top: '110%', left: 0, right: 0, background: 'white', zIndex: 100, border: '1px solid #e2e8f0', borderRadius: '15px', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)', overflow: 'hidden' };
const sugItem = { padding: '12px 20px', cursor: 'pointer', borderBottom: '1px solid #f1f5f9', fontSize: '0.9rem', transition: 'background 0.2s' };
const grid = { display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '20px' };
const cardOferta = { background: 'white', borderRadius: '20px', overflow: 'hidden', border: '1px solid #e2e8f0', transition: 'transform 0.2s' };
const imgStyle = { width: '100%', height: '130px', objectFit: 'cover' };
const btnAdd = { width: '100%', padding: '10px', background: '#1e293b', color: 'white', border: 'none', borderRadius: '10px', cursor: 'pointer', marginTop: '10px', fontWeight: '600' };
const centeredContainer = { maxWidth: '800px', margin: '0 auto' };
const historialList = { display: 'flex', flexDirection: 'column', gap: '15px', marginTop: '10px' };
const historialItem = { display: 'flex', justifyContent: 'space-between', alignItems: 'center', padding: '20px', background: 'white', borderRadius: '18px', border: '1px solid #e2e8f0', boxShadow: '0 2px 4px rgba(0,0,0,0.02)' };

export default PanelCliente;
